            swap((a + l), (a + i));
        }
    }
}

int factorial(int n) {
    if (n == 0) return 1;
    return n * factorial(n - 1);
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    getchar(); // consume newline

    char ***a = malloc(n * sizeof(char **));
    int *perm_counts = calloc(n, sizeof(int));
    int max_perms = 1;

    for (int i = 0; i < n; i++) {
        char line[10];
        fgets(line, 10, stdin);
        line[strcspn(line, "\n")] = '\0';
        int len = strlen(line);
        int fact = factorial(len);
        a[i] = malloc(fact * sizeof(char *));
        permute(line, 0, len - 1, &a[i], &perm_counts[i]);
        max_perms *= perm_counts[i];
    }

    int mn = INT_MAX;
    int *indices = calloc(n, sizeof(int));

    for (int i = 0; i < max_perms; i++) {
        int *nums = malloc(n * sizeof(int));
