            if (nums[j] < min_num) min_num = nums[j];
        }
        int diff = max_num - min_num;
        if (diff < mn) mn = diff;

        free(nums);

        // Update indices
        for (int j = n - 1; j >= 0; j--) {
            if (indices[j] + 1 < perm_counts[j]) {
                indices[j]++;
                break;
            } else {
                indices[j] = 0;
            }
        }
    }

    printf("%d\n", mn);

    // Free memory
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < perm_counts[i]; j++) {
            free(a[i][j]);
        }
        free(a[i]);
    }
    free(a);
    free(perm_counts);
    free(indices);

    return 0;
}
